const router = express.Router()

/**
 * @swagger
 * /items:
 *   get:
 *     tags: ["item"]
 *     summary: Mostra tutti gli elementi
 *     description: Restituisce tutti gli elementi presenti nel database come json array
 *     responses:
 *       200:
 *         description: Lista di prodotti inviata
 *         content:
 *           application/json:
 *             schema:
 *               type: array
 *               items:
 *                 type: object
 *                 properties:
 *                   id:
 *                     type: integer
 *                   fk_utente:
 *                     type: integer
 *                   prezzo:
 *                     type: float
 *                   descrizione:
 *                     type: string
 *
 *       500:
 *         description: Errore interno del server
 */
router.get('/items/:nr', async (req, res) => {
  try {
    const nr = Number(req.params.nr)
    res.statusCode = 200
    const response = await getAllItems()
    res.send(response.slice((nr-1)*30, Math.min(nr*30 -1, (response.length-1))))
  } catch (err) {
    res.statusCode = 401
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify({ error: err }))
  }
})

