/**
 * @swagger
 * /items/{itemId}:
 *   get:
 *     tags: ["item"]
 *     summary: Crea una chat partendo dall'oggetto
 *     description: Ritorna i dettagli di un prodotto specifico
 *     responses:
 *       200:
 *         description: Chat creata con successo
 *         content:
 *           application/json:
 *             schema:
 *               type: object
 *               properties:
 *                 id:
 *                   type: integer
 *                 fk_utente:
 *                   type: integer
 *                 prezzo:
 *                   type: float
 *                 descrizione:
 *                   type: string
 *       500:
 *         description: Errore interno del server
 */

router.post('/items/chats/:itemId', isAuthenticated, async (req, res) => {
  try {
    const itemId = req.params.itemId
    const userId1 = req.session.user.id
    const item = await getItemById(itemId)
    const chatExist = await checkChatExist(item.fk_utente, userId1)

    if (chatExist.length > 0) {
      res.statusCode = 401
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: "Chat già esistente" }))
    }
    const chat = await createChat(userId1, item.fk_utente)

    res.setHeader('Content-Type', 'application/json')
    res.status(201)
    res.end(JSON.stringify(chat))
  } catch (error) {
    console.error(error)
  }
})


/**
 * @swagger
 * /items:
 *   post:
 *     tags: ["item"]
 *     summary: Aggiunge un'oggetto
 *     description: Inserisce un nuovo oggetto nel db
 *     responses:
 *       201:
 *         description: Oggetto aggiunto con successo
 *         content:
 *           application/json:
 *             schema:
 *               type: object
 *               properties:
 *                 prod_id:
 *                   type: integer
 *       500:
 *         description: Errore interno del server
 */
router.post('/items', isAuthenticated,  upload.single('prod_img'), async (req, res) => {
  try {
    const { name, price, description, fk_tag } = req.body
    if ( !name || !price || !description || !fk_tag) {
      res.statusCode = 401
      res.setHeader('Content-Type', 'application/json')
      return res.end(
        JSON.stringify({
          error: 'Non sono stati inseriti tutti i parametri necessari per eseguire la funzione'
        })
      )
    }

    const userId = req.session.user.id
    const picture = `http://127.0.0.1:${process.env.BACKEND_PORT}/uploads/items/${req.file.filename}`
    const now = new Date()
    const formattedDate = now.getFullYear() +
      '-' +
      (now.getMonth() + 1) +
      '-' +
      now.getDate() +
      ' ' +
      now.getHours() +
      ':' +
      now.getMinutes()

    const createdItem = await createItem(picture, name, price, description, formattedDate, userId, fk_tag)

    res.statusCode = 201
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify(createdItem))
  } catch (err) {
    console.error(err)
    res.statusCode = 500
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify({ error: err }))
  }
})

/**
 * @swagger
 * /items/{itemId}:
 *   delete:
 *     tags: ["item"]
 *     summary: Rimuove un prodotto dal database
 *     description: Rimuove un prodotto dal database in base all'id e lo ritorna
 *     responses:
 *       204:
 *         description: Prodotto eliminato
 *       500:
 *         description: Errore interno del server
 */
router.delete('/items/:itemId', isAuthenticated, async (req, res) => {
  try {
    const itemId = req.params.itemId
    const userId = req.session.user.id
    const existingItem = await getItemById(itemId)

    if (existingItem === undefined) {
      res.statusCode = 401
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: 'Oggetto inesistente' }))
    }

    if (existingItem.fk_utente !== userId) {
      res.status(500)
      return res.end()
    }

    res.send(await deleteItemById(itemId))
  } catch (err) {
    console.error(err)
    res.statusCode = 500
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify({ error: err }))
  }
})

/**
 * @swagger
 * /items/{itemId}/favorites:
 *   post:
 *     tags: ["item"]
 *     summary: Aggiunge un'oggetto alla lista dei preferiti
 *     description: Aggiungere un record dove l'utente e l'oggetto sono collegati
 *     responses:
 *       204:
 *         description: Oggetto aggiunto con successo
 *       500:
 *         description: Errore interno del server
 */
router.post('/items/favorites/:iteamId', isAuthenticated, async (req, res) => {
  try {

    const userId = req.session.user.id
    const itemId = req.params.iteamId
    const item = await getItemById(itemId)
    if (item === undefined) {
      res.statusCode = 401
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: 'Oggetto inesistente' }))
    }
    const checkFavorite = await isItemInFavorites(userId, itemId)
    if (checkFavorite.length === 0) {
      res.statusCode = 204
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: 'Oggetto già presente fra i preferiti' }))
    }
    const add = await addItemToFavorites(userId, itemId)
    res.send(add)
  } catch (err) {
    console.error(err)
    res.statusCode = 500
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify({ error: err }))
  }
})

/**
 * @swagger
 * /items/{itemId}/favorites:
 *   delete:
 *     tags: ["item"]
 *     summary: Rimuove un prodotto dai preferiti
 *     description: Cancella un record dalla tabella che collega il prodotto ai preferiti dell'utente
 *     responses:
 *       204:
 *         description: Prodotto eliminato dai Preferiti
 *       500:
 *         description: Errore interno del server
 */
router.delete('/items/favorites/:itemId', isAuthenticated, async (req, res) => {
  try {
    const userId = req.session.user.id
    const itemId = req.params.itemId
    const item = await getItemById(itemId)
    if (item === undefined) {
      res.statusCode = 401
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: 'Oggetto inesistente' }))
    }
    const checkFavorite = await isItemInFavorites(userId, itemId)
    if (checkFavorite.length === 0) {
      res.statusCode = 400
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: 'Oggetto non presente fra i preferiti' }))
    }

    res.statusCode = 204
    res.send(await removeItemFromFavorites(userId, itemId))
  } catch (err) {
    console.error(err)
    res.statusCode = 500
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify({ error: err }))
  }
})

