/**
 * @swagger
 * /items/{itemId}/cart:
 *   delete:
 *     tags: ["item"]
 *     summary: Rimuove un prodotto dal carrello
 *     description: Cancellare un record della tabella carrello
 *     responses:
 *       204:
 *         description: Prodotto eliminato dai Preferiti
 *       500:
 *         description: Errore interno del server
 */
router.delete('/items/cart/:itemId', isAuthenticated, async (req, res) => {
  try {
    const userId = req.session.user.id
    const itemId = req.params.itemId
    const item = await getItemById(itemId)
    if (item === undefined) {
      res.statusCode = 401
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: 'Oggetto inesistente' }))
    }
    const checkCart = await isItemInCart(userId, itemId)
    if (checkCart.length === 0) {
      res.statusCode = 400
      res.setHeader('Content-Type', 'application/json')
      return res.end(JSON.stringify({ error: 'Oggetto non presente nel carello' }))
    }

    res.send(await removeItemFromCart(userId, itemId))
  } catch (err) {
    console.error(err)
    res.statusCode = 500
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify({ error: err }))
  }
})

