/**
 * @swagger
 * /items/update:
 *   patch:
 *     tags: ["item"]
 *     summary: Modifica un'elemento
 *     description: Modifica delle informazioni di un'elemento
 *     responses:
 *       200:
 *         description: Info Modificate
 *       500:
 *         description: Errore interno del server
 */
router.patch('/items/update', isAuthenticated, async (req, res) => {
  try {
    const { id: itemId, price, picture, description, name, fk_tag } = req.body


    if (!picture || !name || !price || !description || !fk_tag || !itemId) {
      res.statusCode = 401
      res.setHeader('Content-Type', 'application/json')
      return res.end(
        JSON.stringify({
          error: 'Non sono stati inseriti tutti i parametri necessari per eseguire la funzione'
        })
      )
    }

    const existingItem = await getItemById(itemId)

    if (existingItem === undefined) {
      res.status(500)
      return res.end()
    }

    if (existingItem.fk_utente !== req.session.user.id) {
      res.status(500)
      return res.end()
    }

    const updatedItem = await updateItemById(itemId, price, picture, description, name, fk_tag)

    res.statusCode = 200
    res.setHeader('Content-Type', 'application/json')
    res.end()
  } catch (err) {
    console.error(err)
    res.statusCode = 500
    res.setHeader('Content-Type', 'application/json')
    res.end(JSON.stringify({ error: err }))
  }
})

